pub fn handle_syscall(uctx: &mut UserContext) {
    let Some(sysno) = Sysno::new(uctx.sysno()) else {
        // renameat (38) exists in the Linux generic syscall ABI (used by
        // riscv64/loongarch64) but is missing from the syscalls crate v0.8.1.
        // musl's renameat()/rename() call syscall(38, ...) on these arches.
        // Handle it via the raw number so it doesn't return ENOSYS.
        if uctx.sysno() == 38 {
            let result = sys_renameat2(
                uctx.arg0() as _,
                uctx.arg1() as _,
                uctx.arg2() as _,
                uctx.arg3() as _,
                0,
            );
            debug!("Syscall renameat(38) return {result:?}");
            uctx.set_retval(
                result.unwrap_or_else(|err| -LinuxError::from(err).code() as _) as _,
            );
            return;
        }
        warn!("Invalid syscall number: {}", uctx.sysno());
        uctx.set_retval(-LinuxError::ENOSYS.code() as _);
        return;
    };

    trace!("Syscall {sysno:?}");

    let result = match sysno {
        // fs ctl
        Sysno::ioctl => sys_ioctl(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        Sysno::chdir => sys_chdir(uctx.arg0() as _),
